import{p as t,bh as a,I as i,U as o}from"./chunks/framework.BpabEsSf.js";const p=JSON.parse('{"title":"Карта документации","description":"","frontmatter":{"title":"Карта документации","date":"2025-05-01T23:00:00.000Z","permalink":"/reference/catalogue"},"headers":[],"relativePath":"ru/02.Configuration/01.Documentation Map.md","filePath":"ru/02.Configuration/01.Documentation Map.md","lastUpdated":null}'),r={name:"ru/02.Configuration/01.Documentation Map.md"};function n(l,e,c,d,s,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ru\\02.Configuration\\01.Documentation Map.md for this page in Markdown format</div><h1 id="🗺️-глобальная-навигация-по-документации-monica" tabindex="-1">🗺️ Глобальная навигация по документации Monica <a class="header-anchor" href="#🗺️-глобальная-навигация-по-документации-monica" aria-label="Permalink to &quot;🗺️ Глобальная навигация по документации Monica&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Краткое содержание</p><p>Добро пожаловать в официальный центр документации экосистемы локального хранилища <code>Monica</code>. Эта матрица служит вашей точкой быстрого доступа к основным руководствам пользователя, архитектурным фреймворкам и техническим спецификациям разработки нашего программного обеспечения.</p></div><h2 id="🚀-01-введение-и-руководства-guide" tabindex="-1">🚀 01. Введение и руководства (Guide) <a class="header-anchor" href="#🚀-01-введение-и-руководства-guide" aria-label="Permalink to &quot;🚀 01. Введение и руководства (Guide)&quot;">​</a></h2><p>Этот раздел содержит базовые обзоры проекта, глобальные концепции дизайна и практические руководства по повседневному использованию, адаптированные для конечных пользователей.</p><ul><li><strong><a href="/ru/guide/intro.html">📖 О проекте</a></strong> * <em>Локально-ориентированное хранилище, объединяющее экосистемы Bitwarden и KeePass. Полный обзор функциональных возможностей, благодарности open-source сообществу и правовые положения.</em></li><li><strong><a href="/ru/guide/overview.html">🎯 Обзор интерфейса</a></strong> * <em>Быстрое ознакомление с границами основных возможностей и макетами интерфейса (UI) клиентского приложения и расширений для браузера.</em></li><li><strong><a href="/ru/guide/quickstart.html">📝 Быстрый старт</a></strong> * <em>Начните с нуля и мгновенно запустите Monica в работу.</em></li></ul><h2 id="🛠️-02-спецификации-для-разработчиков-и-технические-стандарты-developer-specifications" tabindex="-1">🛠️ 02. Спецификации для разработчиков и технические стандарты (Developer Specifications) <a class="header-anchor" href="#🛠️-02-спецификации-для-разработчиков-и-технические-стандарты-developer-specifications" aria-label="Permalink to &quot;🛠️ 02. Спецификации для разработчиков и технические стандарты (Developer Specifications)&quot;">​</a></h2><p>Специально разработано для участников open-source сообщества, сторонних разработчиков и продвинутых пользователей, проводящих аудит структур конфиденциальности данных.</p><ul><li><strong><a href="/ru/reference/webdav-backup-specification.html">📦 Спецификация формата резервного копирования WebDAV</a></strong> * <em>Разбор потоков межплатформенной синхронизации! Подробное описание структуры архивов стандартного <code>.zip</code> и бинарного <code>.enc.zip</code>, схемы полей JSON, криптографических потоков AES-256-GCM и каскадной логики восстановления при сбоях.</em></li><li><strong><a href="/ru/reference/android-storage-security.html">🔄 Технический документ по локальному хранению и шифрованию</a></strong> * <em>Анализ технической реализации, охватывающий управление песочницей локального хранения и низкоуровневые криптографические схемы.</em></li></ul><h2 id="📈-статус-эволюции-проекта" tabindex="-1">📈 Статус эволюции проекта <a class="header-anchor" href="#📈-статус-эволюции-проекта" aria-label="Permalink to &quot;📈 Статус эволюции проекта&quot;">​</a></h2><div class="center tk-center-container"><table tabindex="0"><thead><tr><th style="text-align:center;">Текущая основная версия</th><th style="text-align:center;">Системные требования к платформе</th><th style="text-align:center;">Тип open-source лицензии</th></tr></thead><tbody><tr><td style="text-align:center;"><code>v1.4.0</code></td><td style="text-align:center;">Android 8.0+ / Web</td><td style="text-align:center;"><a href="./LICENSE.html">GNU GPL v3.0</a></td></tr></tbody></table></div>',11)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
